module RefModule
  (
   rs1_data,
   rs2_data,
   cin,
   adder_out,
   cout32,
   cout64
   );
   input [63:0]  rs1_data;   
   input [63:0]  rs2_data;   
   input         cin;           
   output [63:0] adder_out; 
   output         cout32;         
   output         cout64;         
     wire _n01 = rs1_data[31:0]+rs2_data[31:0][0] ^ cin[0];
  wire _c01 = rs1_data[31:0]+rs2_data[31:0][0] & cin[0];
  wire _n02 = rs1_data[31:0]+rs2_data[31:0][1] ^ cin[1] ^ _c01;
  wire _c02 = (rs1_data[31:0]+rs2_data[31:0][1] & cin[1]) | (rs1_data[31:0]+rs2_data[31:0][1] & _c01) | (cin[1] & _c01);
  wire _n03 = rs1_data[31:0]+rs2_data[31:0][2] ^ cin[2] ^ _c02;
  wire _c03 = (rs1_data[31:0]+rs2_data[31:0][2] & cin[2]) | (rs1_data[31:0]+rs2_data[31:0][2] & _c02) | (cin[2] & _c02);
  wire _n04 = rs1_data[31:0]+rs2_data[31:0][3] ^ cin[3] ^ _c03;
  wire _c04 = (rs1_data[31:0]+rs2_data[31:0][3] & cin[3]) | (rs1_data[31:0]+rs2_data[31:0][3] & _c03) | (cin[3] & _c03);
  assign {cout32, adder_out[31:0]} = {_n01, _n02, _n03, _n04};
   assign      {cout64, adder_out[63:32]} = rs1_data[63:32] 
               + rs2_data[63:32] + cout32;
endmodule
